// Create a label on Mars with a line connecting text to planet
var marsLabel = LabelMgr.labelObject("Mars - Red Planet", "Mars", true, 16, "#ff6666", "NE", -1, "Line");
core.debug("Mars label ID: " + marsLabel);

// Create a simple label attached to Sirius
var siriusLabel = LabelMgr.labelObject("Sirius", "Sirius", true, 14, "#ffffff", "E");

// Create a label that auto-deletes after 5 seconds
var tempLabel = LabelMgr.labelObject("Temporary Note", "Jupiter", true, 12, "#ffff00", "N", -1, "TextOnly", false, 5000);

// Hide the label later
LabelMgr.setLabelShow(marsLabel, false);

// Change text dynamically
LabelMgr.setLabelText(marsLabel, "Mars - Now Visible!");

// Create a gold-colored label on Venus
var gold = core.vec3f(1.0, 0.84, 0.0);
var venusLabel = LabelMgr.labelObject("Evening Star", "Venus", true, 16, gold, "NW");

// Create a bright red label with a line to the Moon
var red = core.vec3f(1.0, 0.0, 0.0);
var moonLabel = LabelMgr.labelObject("🌙 Moon", "Moon", true, 18, red, "N", -1, "Line");

// Create a purple label for Jupiter
var purple = core.vec3f(0.7, 0.3, 0.8);
var jupiterLabel = LabelMgr.labelObject("Jupiter", "Jupiter", true, 14, purple, "SE");

// Label the North point on the horizon
var northLabel = LabelMgr.labelHorizon("North", 0, 0, true, 16, "#ffffff");

// Label the East point
var eastLabel = LabelMgr.labelHorizon("East", 90, 0, true, 16, "#ffffff");

// Label the South point
var southLabel = LabelMgr.labelHorizon("South", 180, 0, true, 16, "#ffffff");

// Label the West point
var westLabel = LabelMgr.labelHorizon("West", 270, 0, true, 16, "#ffffff");

// Label a mountain peak at 30° altitude toward the southwest
var mountainLabel = LabelMgr.labelHorizon("Mount Everest", 225, 30, true, 14, "#88ff88");

// Create a temporary zenith marker (disappears after 10 seconds)
var zenithLabel = LabelMgr.labelHorizon("ZENITH", 0, 90, true, 12, "#ffff00", false, 10000);

// Create a cyan-colored label at the celestial equator on the horizon
var cyan = core.vec3f(0.0, 0.8, 0.9);
var equatorLabel = LabelMgr.labelHorizon("Equator crossing", 90, 0, true, 14, cyan);

// Create a bright orange label for sunset direction
var orange = core.vec3f(1.0, 0.65, 0.0);
var sunsetLabel = LabelMgr.labelHorizon("Sunset", 270, 0, true, 16, orange);

// Create a green label for a landmark
var green = core.vec3f(0.3, 0.9, 0.3);
var landmarkLabel = LabelMgr.labelHorizon("My House", 120, 5, true, 12, green);

// Mark the position of the Andromeda Galaxy (M31)
var m31Label = LabelMgr.labelEquatorial("Andromeda Galaxy (M31)", "0h42m44s", "+41°16′09″", true, 14, "#ffcc88", "NE");

// Mark the position of the Orion Nebula (M42)
var m42Label = LabelMgr.labelEquatorial("Orion Nebula (M42)", "5h35m17s", "-5°23′28″", true, 12, "#ff8888", "NW");

// Mark the North Celestial Pole (J2000)
var ncpLabel = LabelMgr.labelEquatorial("North Celestial Pole", "0h", "+90°", true, 14, "#ffffff", "C");

// Mark the Pleiades (M45)
var m45Label = LabelMgr.labelEquatorial("Pleiades (M45)", "3h47m24s", "+24°07′00″", true, 13, "#88ccff", "N");

// Mark a position in current date coordinates (not J2000)
var customLabel = LabelMgr.labelEquatorial("Custom Point", "12h30m", "+45°", true, 12, "#00ff00", "E", -1, false, 0, false);

// Mark the galactic center position in gold
var gold = core.vec3f(1.0, 0.84, 0.0);
var galacticCenter = LabelMgr.labelEquatorial("Galactic Center", "17h45m40s", "-29°00′28″", true, 16, gold, "C");

// Mark the Vega position in light blue
var lightBlue = core.vec3f(0.5, 0.7, 1.0);
var vegaLabel = LabelMgr.labelEquatorial("Vega (α Lyrae)", "18h36m56s", "+38°47′01″", true, 14, lightBlue, "NE");

// Mark the Crab Nebula (M1) in orange
var orange = core.vec3f(1.0, 0.65, 0.0);
var crabLabel = LabelMgr.labelEquatorial("Crab Nebula (M1)", "5h34m32s", "+22°00′52″", true, 12, orange, "NW");

// Create a title banner at the top of the screen
var titleLabel = LabelMgr.labelScreen("★ My Stellarium Presentation ★", 10, 10, true, 20, "#ffcc00");

// Get screen dimensions using core functions
var screenWidth = core.getScreenWidth();
var screenHeight = core.getScreenHeight();

// Create a status message at the bottom-left corner
var statusLabel = LabelMgr.labelScreen("Tracking Mars...", 10, screenHeight - 30, true, 12, "#88ff88");

// Create a centered title
var centeredTitle = LabelMgr.labelScreen("Welcome!", screenWidth / 2 - 50, 50, true, 24, "#ffffff");

// Create a temporary notification (auto-deletes after 3 seconds)
var notification = LabelMgr.labelScreen("Event recorded!", 100, 100, true, 16, "#ffffff", false, 3000);

// Hide the title later
LabelMgr.setLabelShow(titleLabel, false);

// Update label text dynamically
LabelMgr.setLabelText(statusLabel, "Tracking Jupiter...");

// Create a centered title in gold color
var gold = core.vec3f(1.0, 0.84, 0.0);
var screenWidth = core.getScreenWidth();
var titleLabel = LabelMgr.labelScreen("Welcome to Stellarium", screenWidth / 2 - 100, 20, true, 24, gold);

// Create a footer in cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
var screenHeight = core.getScreenHeight();
var footerLabel = LabelMgr.labelScreen("Press F1 for help", 10, screenHeight - 25, true, 10, cyan);

// Create a warning message in red
var red = core.vec3f(1.0, 0.2, 0.2);
var warningLabel = LabelMgr.labelScreen("⚠ Warning: Low Battery", screenWidth - 200, 10, true, 12, red, false, 5000);

var labelId = LabelMgr.labelObject("Test Label", "Mars", true);

if(LabelMgr.getLabelShow(labelId)) {
    core.debug("Label is visible");
} else {
    core.debug("Label is hidden");
}

// Check if a label exists (returns false for invalid IDs)
if(!LabelMgr.getLabelShow(99999)) {
    core.debug("Label ID 99999 does not exist");
}

var labelId = LabelMgr.labelObject("Temporary Label", "Jupiter", true);

core.wait(2);
// Hide the label after 2 seconds
LabelMgr.setLabelShow(labelId, false);

core.wait(2);
// Show it again after another 2 seconds
LabelMgr.setLabelShow(labelId, true);

// Create a label that updates dynamically
var counterLabel = LabelMgr.labelScreen("Count: 0", 10, 10, true, 14, "#ffffff");

// Simple counter using loop (Note: core.wait in loop may not work as expected in all versions)
LabelMgr.setLabelText(counterLabel, "Count: 1");
core.wait(1);
LabelMgr.setLabelText(counterLabel, "Count: 2");
core.wait(1);
LabelMgr.setLabelText(counterLabel, "Count: 3");

// Update an object label with current altitude information
var marsLabel = LabelMgr.labelObject("Mars", "Mars", true);
var marsInfo = core.getObjectInfo("Mars");
if(marsInfo) {
    var altDegrees = parseFloat(marsInfo["altitude"]);
    LabelMgr.setLabelText(marsLabel, "Mars - Alt: " + altDegrees.toFixed(1) + "°");
}

// Create a temporary label
var tempLabel = LabelMgr.labelObject("Temporary Note", "Saturn", true);

// Wait 5 seconds (simulate a long operation)
core.debug("Label created, waiting 5 seconds...");

// In a real script, you would use core.wait() or a timer
// For this example, we assume 5 seconds have passed

// Delete it
LabelMgr.deleteLabel(tempLabel);
core.debug("Label deleted");

// Safe deletion with existence check (deleteLabel does nothing for invalid IDs)
LabelMgr.deleteLabel(99999); // No error, just ignored

// Create multiple labels
var label1 = LabelMgr.labelObject("Label 1", "Mars", true);
var label2 = LabelMgr.labelObject("Label 2", "Jupiter", true);
var label3 = LabelMgr.labelHorizon("Label 3", 90, 30, true);
var label4 = LabelMgr.labelScreen("Label 4", 10, 10, true, 12, "#ffffff");

core.debug("Created 4 labels");

// Clean up all labels at the end of the script
var deletedCount = LabelMgr.deleteAllLabels();
core.debug("Deleted " + deletedCount + " labels");

// Use at the end of a presentation
function cleanup() {
    var count = LabelMgr.deleteAllLabels();
    core.debug("Presentation cleanup complete. Removed " + count + " labels.");
}

